using DiagnosticTool.Utilities.VectorCdd.Common; using DiagnosticTool.Utilities.VectorCdd.XmlParser;  using Microsoft.VisualStudio.TestTools.UnitTesting;  namespace DiagnosticTool.Utilities.VectorCdd.DataTypes;  [TestClass] public class MultiplexerTests {     /// <summary>     /// Multiplexer 选择器匹配 case 时，应返回 case 的结构数据     /// </summary>     [TestMethod]     public void Convert_SelectCase_ReturnsCaseStructure()     {         var xml = """             <MUXDT>             <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>             <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>             <STRUCTURE>               <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>               <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>               <DATAOBJ>                 <NAME><TUV xml:lang='en-US'>Default Value</TUV></NAME>                 <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>               </DATAOBJ>             </STRUCTURE>             <CASE s='1' e='1'>               <STRUCTURE>                 <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <DATAOBJ>                   <NAME><TUV xml:lang='en-US'>Case1 Value</TUV></NAME>                   <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                   <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                 </DATAOBJ>               </STRUCTURE>             </CASE>             <CASE s='2' e='2'>               <STRUCTURE>                 <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <DATAOBJ>                   <NAME><TUV xml:lang='en-US'>Case2 Value</TUV></NAME>                   <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                   <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                 </DATAOBJ>               </STRUCTURE>             </CASE>             </MUXDT>             """;         var mux = xml.DeserializeXmlToObject<Multiplexer>();         // 选择器 = 0x01（case 1），剩余数据 = 0xAB         var result = mux.Convert(Convert.FromHexString("01AB"));          Assert.IsNotNull(result);         Assert.IsTrue(result.IsSuccessful);     }      /// <summary>     /// Multiplexer 选择器不匹配任何 case 时，应返回默认结构     /// </summary>     [TestMethod]     public void Convert_DefaultCase_ReturnsDefaultStructure()     {         var xml = """             <MUXDT>             <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>             <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>             <STRUCTURE>               <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>               <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>               <DATAOBJ>                 <NAME><TUV xml:lang='en-US'>Default Value</TUV></NAME>                 <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>               </DATAOBJ>             </STRUCTURE>             <CASE s='1' e='1'>               <STRUCTURE>                 <DATAOBJ>                   <NAME><TUV xml:lang='en-US'>Case1 Value</TUV></NAME>                   <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                   <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                 </DATAOBJ>               </STRUCTURE>             </CASE>             </MUXDT>             """;         var mux = xml.DeserializeXmlToObject<Multiplexer>();         // 选择器 = 0x99（不匹配任何 case），使用默认结构         var result = mux.Convert(Convert.FromHexString("99AB"));          Assert.IsNotNull(result);         Assert.IsTrue(result.IsSuccessful);     }      /// <summary>     /// 验证 Multiplexer.Convert 不再死循环（修复递归 bug 后）     /// </summary>     [TestMethod]     public void Convert_NoInfiniteRecursion_CompletesSuccessfully()     {         var xml = """             <MUXDT>             <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>             <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='dec' qty='atom' sz='no' minsz='1' maxsz='1'/>             <STRUCTURE>               <DATAOBJ>                 <NAME><TUV xml:lang='en-US'>Default</TUV></NAME>                 <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                 <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>               </DATAOBJ>             </STRUCTURE>             <CASE s='0' e='0'>               <STRUCTURE>                 <DATAOBJ>                   <NAME><TUV xml:lang='en-US'>Case0</TUV></NAME>                   <CVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                   <PVALUETYPE bl='8' bo='12' enc='uns' sig='0' df='hex' qty='atom' sz='no' minsz='1' maxsz='1'/>                 </DATAOBJ>               </STRUCTURE>             </CASE>             </MUXDT>             """;         var mux = xml.DeserializeXmlToObject<Multiplexer>();          // 如果有递归 bug，这行会抛 StackOverflowException         // 使用 Task 限制执行时间以捕获死循环         var task = Task.Run(() => mux.Convert(Convert.FromHexString("00AA")));         var completed = task.Wait(TimeSpan.FromSeconds(5));          Assert.IsTrue(completed, "Convert 方法执行超时，可能存在递归死循环");         Assert.IsTrue(task.Result.IsSuccessful);     } } 